// ============================================================
// PASO 1: Parsear asunto y extraer NIT / NOMBRE PRESTADOR
// Formato esperado: 'RESULTADOS PROSTATA - NOMBRE IPS - NIT'
// Robusto: soporta nombres con guiones
// ============================================================
const item = $input.first().json;

const asunto = (item.body?.asunto || item.asunto || '').toString().toUpperCase().trim();
const remitente = item.body?.remitente || item.remitente || '';
const excelBase64 = item.body?.excel_base64 || item.excel_base64 || '';
const nombreArchivo = item.body?.nombre_archivo || item.nombre_archivo || 'reporte.xlsx';

// Parseo robusto: NIT = última parte, NOMBRE = todo lo del medio
const partes = asunto.split('-').map(p => p.trim());

let nitPrestador = '';
let nombrePrestador = '';
let errorAsunto = '';

if (partes.length < 3) {
  errorAsunto = `El asunto "${asunto}" no cumple el formato: RESULTADOS PROSTATA - NOMBRE IPS - NIT`;
} else {
  nitPrestador = partes[partes.length - 1].trim();
  nombrePrestador = partes.slice(1, partes.length - 1).join('-').trim();

  // Validar que el asunto contenga PROSTATA
  if (!asunto.includes('PROSTATA')) {
    errorAsunto = `El asunto no contiene la palabra PROSTATA`;
  }
  // Validar que NIT sea numérico
  if (!/^\d+$/.test(nitPrestador)) {
    errorAsunto = `El NIT "${nitPrestador}" no es válido (debe ser numérico)`;
  }
}

return [{
  json: {
    asunto,
    remitente,
    excelBase64,
    nombreArchivo,
    nitPrestador,
    nombrePrestador,
    errorAsunto,
    asunoValido: errorAsunto === ''
  }
}];

// ============================================================
// PASO 2: Decodificar Excel base64 y leer todas las filas
// Usa la librería xlsx ya disponible en n8n
// ============================================================
const XLSX = require('xlsx');

const { excelBase64, nombreArchivo, nitPrestador, nombrePrestador, remitente, asunto } = $input.first().json;

// Decodificar base64
const buffer = Buffer.from(excelBase64, 'base64');
const workbook = XLSX.read(buffer, { type: 'buffer', cellDates: false });

// Leer primera hoja (Tabla1)
const sheetName = workbook.SheetNames[0];
const sheet = workbook.Sheets[sheetName];
const filas = XLSX.utils.sheet_to_json(sheet, { defval: '' });

// Guardar workbook original en base64 para reutilizarlo después
const workbookBase64 = Buffer.from(XLSX.write(workbook, { type: 'buffer', bookType: 'xlsx' })).toString('base64');

return [{
  json: {
    filas,
    totalFilas: filas.length,
    workbookBase64,
    nombreArchivo,
    nitPrestador,
    nombrePrestador,
    remitente,
    asunto,
    sheetName
  }
}];

// ============================================================
// PASO 3: Validar cada fila del Excel
// Detecta todos los errores por fila y clasifica:
//   - filasValidas: pasan todas las validaciones locales
//   - filasConError: tienen al menos un error
// La validación de usuario activo en EPS se hace después
// ============================================================

const { filas, workbookBase64, nombreArchivo, nitPrestador, nombrePrestador, remitente, asunto, sheetName } = $input.first().json;

const TIPOS_DOCUMENTO_VALIDOS = ['CC', 'CE', 'PA', 'RC', 'TI', 'CD', 'MS', 'AS', 'NU', 'PE'];

// Convertir serial de Excel a fecha ISO
const serialToISO = (serial) => {
  if (!serial && serial !== 0) return null;
  const num = typeof serial === 'string' ? parseInt(serial.replace(/[^0-9]/g, '')) : serial;
  if (isNaN(num) || num < 1) return null;
  const date = new Date(Date.UTC(1899, 11, 30) + num * 86400000);
  if (isNaN(date.getTime())) return null;
  return date.toISOString().split('T')[0];
};

const esSerialFechaValido = (val) => {
  if (val === '' || val === null || val === undefined) return false;
  // Puede ser número serial o string de fecha
  if (typeof val === 'number') return val > 1 && val < 200000;
  if (typeof val === 'string') {
    // Intentar como serial
    const n = parseInt(val);
    if (!isNaN(n) && n > 1) return true;
    // Intentar como fecha ISO
    return !isNaN(Date.parse(val));
  }
  return false;
};

const filasValidas = [];
const filasConError = [];

filas.forEach((fila, index) => {
  const errores = [];
  const numeroFila = index + 2; // +2 porque fila 1 es encabezado

  // Saltar filas completamente vacías
  const todosVacios = Object.values(fila).every(v => v === '' || v === null || v === undefined);
  if (todosVacios) return;

  // ---- VALIDACIONES ----

  // 1. TIPO IDENTIFICACION
  const tipoDoc = (fila['TIPO IDENTIFICACION'] || '').toString().trim().toUpperCase();
  if (!tipoDoc) {
    errores.push('Tipo de identificación vacío');
  } else if (!TIPOS_DOCUMENTO_VALIDOS.includes(tipoDoc)) {
    errores.push(`Tipo de identificación inválido: "${tipoDoc}". Válidos: ${TIPOS_DOCUMENTO_VALIDOS.join(', ')}`);
  }

  // 2. IDENTIFICACION
  const documento = (fila['IDENTIFICACION'] || '').toString().replace(/\D/g, '').trim();
  if (!documento) {
    errores.push('Número de identificación vacío');
  } else if (documento.length < 5) {
    errores.push(`Número de identificación muy corto: "${documento}"`);
  }

  // 3. PRIMER NOMBRE
  if (!(fila['PRIMER NOMBRE'] || '').toString().trim()) {
    errores.push('Primer nombre vacío');
  }

  // 4. PRIMER APELLIDO
  if (!(fila['PRIMER APELLIDO'] || '').toString().trim()) {
    errores.push('Primer apellido vacío');
  }

  // 5. FECHA DE NACIMIENTO
  if (!esSerialFechaValido(fila['FECHA DE NACIMIENTO'])) {
    errores.push('Fecha de nacimiento inválida o vacía');
  }

  // 6. FECHA DE TOMA DEL EXAMEN
  if (!esSerialFechaValido(fila['FECHA DE TOMA DEL EXAMEN'])) {
    errores.push('Fecha de toma del examen inválida o vacía');
  }

  // 7. FECHA DE RESULTADOS DEL EXAMEN
  const campoFechaResultados = fila['FECHA DE RESULTADOS DEL EXAMEN'] || fila['FECHA_DE RESULTADOS_DEL_EXAMEN'] || '';
  if (!esSerialFechaValido(campoFechaResultados)) {
    errores.push('Fecha de resultados del examen inválida o vacía');
  }

  // 8. NOMBRE DEL EXAMEN
  if (!(fila['NOMBRE DEL EXAMEN'] || '').toString().trim()) {
    errores.push('Nombre del examen vacío');
  }

  // 9. RESULTADO DEL EXAMEN
  if (!(fila['RESULTADO PSA'] || fila['RESULTADO BIOPSIA'] || fila['RESULTADO DEL EXAMEN'] || '').toString().trim()) {
    errores.push('Resultado del examen vacío');
  }

  // 10. HERRAMIENTA
  const herramienta = (fila['HERRAMIENTA'] || '').toString().trim();
  if (herramienta && herramienta !== 'FOR-REPORTE-SOSPECHOSO') {
    errores.push(`Campo HERRAMIENTA incorrecto: "${herramienta}". Debe ser: FOR-REPORTE-SOSPECHOSO`);
  }

  // 11. Nº REGISTRO
  const nroRegistro = (fila['Nº REGISTRO'] || fila['N° REGISTRO'] || fila['NUMERO REGISTRO'] || '').toString().trim().toUpperCase();
  if (nroRegistro && !['SI', 'NO'].includes(nroRegistro)) {
    errores.push(`Campo Nº REGISTRO incorrecto: "${nroRegistro}". Debe ser SI o NO`);
  }

  // Convertir fechas para procesamiento posterior
  const filaConFechas = {
    ...fila,
    tipo_documento: tipoDoc,
    documento: documento,
    primer_nombre: (fila['PRIMER NOMBRE'] || '').toString().trim().toUpperCase(),
    segundo_nombre: (fila['SEGUNDO NOMBRE'] || '').toString().trim().toUpperCase(),
    primer_apellido: (fila['PRIMER APELLIDO'] || '').toString().trim().toUpperCase(),
    segundo_apellido: (fila['SEGUNDO APELLIDO'] || '').toString().trim().toUpperCase(),
    fecha_nacimiento: serialToISO(fila['FECHA DE NACIMIENTO']),
    fecha_toma_examen: serialToISO(fila['FECHA DE TOMA DEL EXAMEN']),
    fecha_resultados: serialToISO(campoFechaResultados),
    telefono: (fila['TELEFONO'] || '').toString().replace(/\D/g, ''),
    regional: (fila['REGIONAL'] || '').toString().trim().toUpperCase(),
    municipio: (fila['MUNICIPIO'] || '').toString().trim().toUpperCase(),
    nombre_examen: (fila['NOMBRE DEL EXAMEN'] || '').toString().trim().toUpperCase(),
    resultado_psa: (fila['RESULTADO PSA'] || '').toString().trim(),
    resultado_biopsia: (fila['RESULTADO BIOPSIA'] || '').toString().trim(),
    nit_prestador: nitPrestador,
    nombre_prestador: nombrePrestador,
    numero_fila: numeroFila,
    errores_validacion: errores
  };

  if (errores.length === 0) {
    filasValidas.push(filaConFechas);
  } else {
    filasConError.push(filaConFechas);
  }
});

return [{
  json: {
    filasValidas,
    filasConError,
    totalValidas: filasValidas.length,
    totalConError: filasConError.length,
    workbookBase64,
    nombreArchivo,
    nitPrestador,
    nombrePrestador,
    remitente,
    asunto,
    sheetName
  }
}];

// ============================================================
// PASO 5: Clasificar resultado de validación EPS
// Agrega el resultado de Mutual a cada fila
// Separa: activos vs inactivos (error de EPS)
// ============================================================
const filaOriginal = $('Split_Filas_Validas').item.json;
const resultadoEPS = $input.first().json;

const estaActivo = resultadoEPS.esta_activo === true || resultadoEPS.esta_activo === 'ACTIVO';
const estadoAfiliado = resultadoEPS.estado_afiliado || resultadoEPS.estadoAfiliado || 'DESCONOCIDO';

return [{
  json: {
    ...filaOriginal,
    estaActivo,
    estadoAfiliado,
    errorEPS: estaActivo ? '' : `Usuario no activo en EPS: estado = ${estadoAfiliado}`,
    // Datos adicionales de Mutual para enriquecer el registro
    codigo_departamento: resultadoEPS.codigo_departamento || '',
    codigo_municipio: resultadoEPS.codigo_municipio || '',
    nombre_departamento: resultadoEPS.nombre_departamento || '',
    nombre_municipio: resultadoEPS.nombre_municipio || '',
    email_paciente: resultadoEPS.email || '',
    direccion: resultadoEPS.direccion_texto || '',
    telefono_movil: resultadoEPS.telefono_movil || '',
    regimen_codigo: resultadoEPS.regimen_codigo || '',
    id_regimen: resultadoEPS.id_regimen || null
  }
}];

// ============================================================
// PASO 7: Determinar si es duplicado
// Si ya existe en BD → marcar como duplicado
// ============================================================
const registroExistente = $input.all();
const filaOriginal = $('Resultado_Validacion_EPS').item.json;

const esDuplicado = registroExistente.length > 0;
const autoIdExistente = esDuplicado ? registroExistente[0].json.auto_id : null;

return [{
  json: {
    ...filaOriginal,
    esDuplicado,
    autoIdExistente
  }
}];

// ============================================================
// PASO: Recolectar filas con error de EPS
// Agrega el error de EPS al array de errores de la fila
// ============================================================
const fila = $input.first().json;

return [{
  json: {
    ...fila,
    errores_validacion: [...(fila.errores_validacion || []), fila.errorEPS]
  }
}];

// ============================================================
// PASO FINAL RAMA VÁLIDAS: Consolidar todos los items
// procesados para pasarlos al generador de reporte
// ============================================================
const items = $input.all();

// Recopilar las filas con error de EPS que fueron procesadas
const filasConErrorEPS = items
  .map(i => i.json)
  .filter(f => f.errores_validacion && f.errores_validacion.length > 0);

return [{ json: { filasConErrorEPS } }];

// ============================================================
// PASO GENERADOR EXCEL DE ERRORES
// Recibe:
//   - filasConError (validación local) desde Validar_Filas_Excel
//   - filasConErrorEPS desde el procesamiento de EPS
// Genera un Excel con columna MOTIVO_ERROR coloreada
// ============================================================
const XLSX = require('xlsx');

// Obtener datos del nodo de validación (tiene workbook original)
const datosValidacion = $('Validar_Filas_Excel').first().json;
const { workbookBase64, nombreArchivo, remitente, nitPrestador, nombrePrestador, asunto,
        filasConError: erroresLocales, filasValidas,
        totalValidas, totalConError } = datosValidacion;

// Obtener errores de EPS si los hay
let erroresEPS = [];
try {
  const epsData = $('Consolidar_Errores_EPS').first();
  erroresEPS = epsData?.json?.filasConErrorEPS || [];
} catch(e) { erroresEPS = []; }

// Combinar todos los errores
const todasFilasConError = [...(erroresLocales || []), ...erroresEPS];
const totalErrores = todasFilasConError.length;
const totalProcesados = (filasValidas || []).length - erroresEPS.length;

if (totalErrores === 0) {
  // No hay errores, no generar Excel
  return [{ json: {
    hayErrores: false,
    remitente, nitPrestador, nombrePrestador, asunto,
    totalProcesados, totalErrores, nombreArchivo
  }}];
}

// Reconstruir workbook original
const buffer = Buffer.from(workbookBase64, 'base64');
const wb = XLSX.read(buffer, { type: 'buffer' });
const sheetName = wb.SheetNames[0];
const ws = wb.Sheets[sheetName];

// Agregar encabezado de columna de errores
const range = XLSX.utils.decode_range(ws['!ref']);
const colError = range.e.c + 1; // columna siguiente al final
const colLetra = XLSX.utils.encode_col(colError);

// Header de la columna de errores
ws[`${colLetra}1`] = {
  v: 'MOTIVO_ERROR',
  t: 's',
  s: {
    font: { bold: true, color: { rgb: 'FFFFFF' } },
    fill: { fgColor: { rgb: 'C0392B' } },
    alignment: { horizontal: 'center' }
  }
};

// Crear mapa de errores por número de fila
const errorPorFila = {};
todasFilasConError.forEach(fila => {
  errorPorFila[fila.numero_fila] = fila.errores_validacion.filter(Boolean).join(' | ');
});

// Para filas válidas, marcar en verde
const filaValida_set = new Set((filasValidas || []).filter(f => !f.errorEPS).map(f => f.numero_fila));

// Recorrer filas y agregar columna
for (let r = range.s.r + 1; r <= range.e.r; r++) {
  const filaNum = r + 1; // +1 porque r es 0-indexed y fila 1 es header
  const celda = `${colLetra}${r + 1}`;

  if (errorPorFila[filaNum]) {
    ws[celda] = {
      v: '❌ ' + errorPorFila[filaNum],
      t: 's',
      s: {
        fill: { fgColor: { rgb: 'FADBD8' } },
        font: { color: { rgb: 'C0392B' } }
      }
    };
    // Colorear toda la fila en rojo claro
    for (let c = range.s.c; c <= range.e.c; c++) {
      const celdaFila = XLSX.utils.encode_cell({ r, c });
      if (ws[celdaFila]) {
        ws[celdaFila].s = ws[celdaFila].s || {};
        ws[celdaFila].s.fill = { fgColor: { rgb: 'FADBD8' } };
      }
    }
  } else if (filaValida_set.has(filaNum)) {
    ws[celda] = {
      v: '✅ Procesado correctamente',
      t: 's',
      s: { fill: { fgColor: { rgb: 'D5F5E3' } } }
    };
    for (let c = range.s.c; c <= range.e.c; c++) {
      const celdaFila = XLSX.utils.encode_cell({ r, c });
      if (ws[celdaFila]) {
        ws[celdaFila].s = ws[celdaFila].s || {};
        ws[celdaFila].s.fill = { fgColor: { rgb: 'D5F5E3' } };
      }
    }
  }
}

// Actualizar rango del sheet
range.e.c = colError;
ws['!ref'] = XLSX.utils.encode_range(range);

// Auto-width para columna de errores
const colsWidth = ws['!cols'] || [];
colsWidth[colError] = { wch: 60 };
ws['!cols'] = colsWidth;

// Exportar a base64
const excelBuffer = XLSX.write(wb, { type: 'buffer', bookType: 'xlsx', cellStyles: true });
const excelBase64Salida = Buffer.from(excelBuffer).toString('base64');

return [{
  json: {
    hayErrores: true,
    excelBase64Salida,
    nombreArchivoErrores: `ERRORES_${nombreArchivo}`,
    remitente,
    nitPrestador,
    nombrePrestador,
    asunto,
    totalProcesados,
    totalErrores,
    resumenErrores: todasFilasConError.map(f => ({
      fila: f.numero_fila,
      identificacion: f.documento || '(vacío)',
      nombre: `${f.primer_nombre || ''} ${f.primer_apellido || ''}`.trim() || '(vacío)',
      errores: f.errores_validacion.filter(Boolean).join(' | ')
    }))
  }
}];

